// ============================================================================
// S32K358 HDQFP-172 Pin Allocation -- Auto-generated 2026-03-13
// ============================================================================
//
// NXP S32K358: Dual Cortex-M7 @ 240MHz, 172-pin HDQFP
// ~142 I/O pins, 5 GPIO ports (PTA-PTE), 3x SAR ADC, 3x eMIOS, 6x CAN FD
//
// SIUL2 MSCR index = port * 32 + pin_number
//   PTA0..31 = MSCR[0..31]     PTB0..31 = MSCR[32..63]
//   PTC0..31 = MSCR[64..95]    PTD0..31 = MSCR[96..127]
//   PTE0..31 = MSCR[128..159]
//
// Pin budget (120 assigned):
//    14 PWM outputs       -- eMIOS1 channels -> TC4427A / DRV8876
//    34 gate driver GPIO  -- push-pull outputs -> TC4427A
//     2 H-bridge control  -- GPIO (nSLEEP, nFAULT)
//    15 switch inputs     -- GPIO input w/ external pull-up
//    49 ADC inputs        -- 46 current sense + 3 sensor (direct, no MUX)
//     2 CAN FD            -- CAN0 TX/RX
//     4 JTAG              -- TMS, TCK, TDI, TDO
//     2 crystal            -- EXTAL (pad 23) / XTAL (pad 25) [dedicated, not GPIO]
//   ~30 power/ground       -- VDD, VSS, VDDA, etc.
//
// Source: NXP S32K358 IOMUX spreadsheet (S32K358_IOMUX.xlsx)
// Generated by: s32k358_pin_allocator.py
// ============================================================================

// --- Port/pin encoding helpers ---
// SIUL2 MSCR index = port_base + pin_number
#define PIN_PTA(n)  ((0u * 32u) + (n))
#define PIN_PTB(n)  ((1u * 32u) + (n))
#define PIN_PTC(n)  ((2u * 32u) + (n))
#define PIN_PTD(n)  ((3u * 32u) + (n))
#define PIN_PTE(n)  ((4u * 32u) + (n))

