// ============================================================================
// ADC Configuration -- 3x SAR ADC instances, direct (no MUX)
// ============================================================================
//
// S32K358 has 3 SAR ADC instances (ADC0, ADC1, ADC2).
// Each INA180A1 output connects directly to an MCU ADC pin -- no analog MUX.
// ADC analog inputs bypass SIUL2 digital mux (hardwired analog paths).
//
// Pin-to-ADC mapping extracted from S32K358_IOMUX.xlsx PeripheralSummaries.
// ============================================================================

// ADC identifier: encodes instance + channel in one byte
// Upper 2 bits = ADC instance (0-2), lower 6 bits = channel number (0-63)
#define ADC_ID(instance, channel) (((instance) << 6) | ((channel) & 0x3F))
#define ADC_INSTANCE(id)          ((id) >> 6)
#define ADC_CHANNEL(id)           ((id) & 0x3F)

